//  SkyOpsLogo.swift
//  SkyOps — brand mark
//
//  The SkyOps winged-aircraft logo, rendered natively from the Figma vector
//  (7 solid-fill paths, viewBox 405.93×324.2) via the existing SVGPath parser
//  — no bundled raster asset. Scales crisply to any size.
//

import SwiftUI

struct SkyOpsLogo: View {
    static let viewBox = CGSize(width: 405.93, height: 324.2)

    private struct Layer { let color: Color; let path: Path }
    private static let layers: [Layer] = rawPaths.map {
        Layer(color: $0.0, path: SVGPath.parse($0.1))
    }

    var body: some View {
        Canvas { ctx, size in
            let s = min(size.width / Self.viewBox.width, size.height / Self.viewBox.height)
            let ox = (size.width - Self.viewBox.width * s) / 2
            let oy = (size.height - Self.viewBox.height * s) / 2
            var g = ctx
            g.translateBy(x: ox, y: oy)
            g.scaleBy(x: s, y: s)
            for layer in Self.layers { g.fill(layer.path, with: .color(layer.color)) }
        }
        .aspectRatio(Self.viewBox.width / Self.viewBox.height, contentMode: .fit)
    }

